insert into public.issued_documents (
  organization_id, counterparty_id, import_batch_id, document_number, issue_date,
  document_type, issuer_name, issuer_tax_id, client_name, recipient_name,
  recipient_tax_id, net_amount, vat_amount, total_amount, notes, payment_term_days,
  due_date, due_month, payment_status, payment_date, payment_method,
  origin_account_or_tax_id, destination_bank, destination_account, source_file_name,
  source_sheet_name, source_row
)
select
  'cd4ebec4-3cf6-40f4-9631-0a5d8fd7a4f2', counterparty.id, source.import_batch_id, source.document_number, source.issue_date,
  source.document_type, source.issuer_name, source.issuer_tax_id, source.client_name,
  source.recipient_name, source.recipient_tax_id, source.net_amount, source.vat_amount,
  source.total_amount, source.notes, source.payment_term_days, source.due_date,
  source.due_month, source.payment_status, source.payment_date, source.payment_method,
  source.origin_account_or_tax_id, source.destination_bank, source.destination_account,
  source.source_file_name, source.source_sheet_name, source.source_row
from source_documents source
left join public.counterparties counterparty
  on counterparty.organization_id = 'cd4ebec4-3cf6-40f4-9631-0a5d8fd7a4f2'
 and counterparty.tax_id = source.recipient_tax_id;

